// Generated by Claude with validated selectors
import { test, expect } from '@playwright/test';

test('MakeMyTrip search flow', async ({ page }) => {
  await page.goto('https://makemytrip.com');

  // Selector validated against actual DOM
  await page.locator('role=tab[text="Flight"]').click();
  await page.locator('role=textbox[label="From"]').fill('Delhi');
  await page.locator('role=option[text="Delhi, India"]').click();

  await page.locator('role=textbox[label="To"]').fill('Bangalore');
  await page.locator('role=option[text="Bangalore, India"]').click();

  await page.locator('role=button[text="Search"]').click();

  await expect(page.locator('role=list[item]')).toContainText('Flight');
});
